<?php
namespace App\Controllers;
use App\Core\Controller;use App\Config\Database;use App\Helpers\{Auth,Csrf,Flash};
final class AuthController extends Controller {public function form():void{$this->view('auth/login');} public function login():void{Csrf::verify();$db=Database::connection();$s=$db->prepare("SELECT u.*,r.nombre rol FROM usuarios u JOIN roles r ON r.id=u.rol_id WHERE u.correo=? AND u.estado=1 LIMIT 1");$s->execute([trim($_POST['correo']??'')]);$u=$s->fetch();if(!$u||!password_verify($_POST['password']??'',$u['password'])){Flash::set('error','Credenciales incorrectas.');$this->redirect('/login');}session_regenerate_id(true);unset($u['password']);$_SESSION['user']=$u;Flash::set('success','Bienvenido, '.$u['nombre']);$this->redirect(in_array($u['rol'],['Administrador','Operador'],true)?'/admin':'/mi-cuenta');} public function register():void{Csrf::verify();$n=trim($_POST['nombre']??'');$e=filter_var($_POST['correo']??'',FILTER_VALIDATE_EMAIL);$p=$_POST['password']??'';if(!$e||strlen($p)<8||$n===''){Flash::set('error','Complete los datos. La contraseña requiere 8 caracteres.');$this->redirect('/login');}$db=Database::connection();try{$s=$db->prepare("INSERT INTO usuarios(rol_id,nombre,correo,password,nacionalidad) VALUES(3,?,?,?,?)");$s->execute([$n,$e,password_hash($p,PASSWORD_DEFAULT),trim($_POST['nacionalidad']??'Panameña')]);Flash::set('success','Cuenta creada. Ya puede iniciar sesión.');}catch(\Throwable){Flash::set('error','El correo ya está registrado.');}$this->redirect('/login');} public function logout():void{session_destroy();session_start();$this->redirect('/');} public function changePassword():void{Auth::requireLogin();Csrf::verify();$p=$_POST['password']??'';if(strlen($p)<8){Flash::set('error','La contraseña debe tener al menos 8 caracteres.');Auth::go('/mi-cuenta');}$s=Database::connection()->prepare("UPDATE usuarios SET password=? WHERE id=?");$s->execute([password_hash($p,PASSWORD_DEFAULT),Auth::id()]);Flash::set('success','Contraseña actualizada.');Auth::go('/mi-cuenta');}}
